288	// chartVersion可以为空，表示获取该套件的最新推送的版本
289	func getAISuiteInRegistry(ctx context.Context, suiteRegistry *db.Repository, name, chartVersion string) (*aisuite.GetAISuiteResp, error) {
290		chart := &model.Artifact{}
291		err := error(nil)
292	
293		if suiteRegistry == nil {
294			return nil, fmt.Errorf("suite registry is nil")
295		}
296		if chartVersion != "" {
297			registryOpts := harbor.DefaultOptions()
298			registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
299			if err != nil {
300				log.Errorf("failed to get registry client: %v", err)
301				return nil, fmt.Errorf("failed to get registry client: %w", err)
302			}
303			chart, err = registryCli.GetClient().GetArtifact(ctx, suiteChartProject, name, chartVersion)
304			if err != nil {
305				log.Errorf("failed to get artifact %s:%s from registry: %v", name, chartVersion, err)
306				return nil, fmt.Errorf("failed to get artifact %s:%s from registry: %w", name, chartVersion, err)
307			}
308		} else {
309			registryOpts := harbor.DefaultOptions().WithPage(1).WithPageSize(1).WithSort("-push_time").WithQuery("tags=~.")
310			registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
311			if err != nil {
312				log.Errorf("failed to get registry client: %v", err)
313				return nil, fmt.Errorf("failed to get registry client: %w", err)
314			}
315			charts, err := registryCli.GetClient().ListArtifacts(ctx, suiteChartProject, name)
316			if err != nil {
317				log.Errorf("failed to list artifacts in registry for suite %s: %v", name, err)
318				return nil, fmt.Errorf("failed to list artifacts in registry for suite %s: %w", name, err)
319			}
320			if len(charts) == 0 {
321				return nil, nil
322			}
323			chart = charts[0]
324		}
325	
326		profile := chartToProfileAISuite(chart)
327		customValueSchema, err := getCustomValueSchema(ctx, suiteRegistry, name, chart.Digest)
328		if err != nil {
329			log.Errorf("failed to get custom value schema for suite %s:%s: %v", name, profile.Version.ChartVersion, err)
330			customValueSchema = nil // 获取schema失败不应该导致整个请求失败，所以这里不返回错误了
331		}
332		versionList, err := getAllVersionsOfAISuiteInRegistry(ctx, suiteRegistry, name)
333		if err != nil {
334			log.Errorf("failed to get all versions of AI Suite in registry for suite %s: %v", name, err)
335			versionList = []*aisuite.AISuiteVersion{profile.Version} // 获取版本列表失败不应该导致整个请求失败，所以这里至少返回当前版本
336		}
337		return &aisuite.GetAISuiteResp{
338			ProfileAISuite:    profile,
339			InCluster:         false,
340			VersionList:       versionList,
341			CustomValueSchema: customValueSchema,
342		}, nil
343	}
