406	func getAllVersionsOfAISuiteInRegistry(ctx context.Context, suiteRegistry *db.Repository, name string) ([]*aisuite.AISuiteVersion, error) {
407		registryOpts := harbor.DefaultOptions().WithPage(1).WithPageSize(100).WithQuery("tags=~.,Type=" + chartArtifactType).WithSort("-push_time")
408		registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
409		if err != nil {
410			log.Errorf("failed to get registry client: %v", err)
411			return nil, err
412		}
413		charts, err := registryCli.GetClient().ListArtifacts(ctx, suiteChartProject, name)
414		if err != nil {
415			log.Errorf("failed to list artifacts in registry for suite %s: %v", name, err)
416			return nil, err
417		}
418		versionList := make([]*aisuite.AISuiteVersion, 0, len(charts))
419		for _, chart := range charts {
420			appVersion, _ := chart.ExtraAttrs["appVersion"].(string)
421			chartVersion, _ := chart.ExtraAttrs["version"].(string)
422			displayVersion := getDisplayVersion(appVersion, chartVersion)
423			versionList = append(versionList, &aisuite.AISuiteVersion{
424				AppVersion:     appVersion,
425				ChartVersion:   chartVersion,
426				DisplayVersion: displayVersion,
427			})
428		}
429		return versionList, nil
430	}
