432	func (c *Controller) getAISuiteInCluster(clusterCode, name, chartVersion, namespace string) (*aisuite.GetAISuiteResp, error) {
433		releaseInCluster, err := c.apiserverGetter.GetHelmReleaseByName(clusterCode, namespace, name)
434		if err != nil {
435			log.Errorf("failed to get helm release [%s:%s] in cluster %s: %v", namespace, name, clusterCode, err)
436			return nil, fmt.Errorf("failed to get helm release in cluster: %w", err)
437		}
438		if releaseInCluster.Labels["DeployedBy"] != "TAPAISuite" {
439			return nil, fmt.Errorf("helm release %s in namespace %s is not deployed by TAPAISuite", name, namespace)
440		}
441		profile := releaseElementToProfileAISuite(releaseInCluster)
442		if chartVersion != "" && profile.Version.ChartVersion != chartVersion {
443			return nil, fmt.Errorf("chart version mismatch for release %s in namespace %s: expected %s, got %s", name, namespace, chartVersion, profile.Version.ChartVersion)
444		}
445		versionList := make([]*aisuite.AISuiteVersion, 0)
446		versionList = append(versionList, profile.Version)
447		return &aisuite.GetAISuiteResp{
448			ProfileAISuite: profile,
449			InCluster:      true,
450			MaxRevision:    releaseInCluster.Revision, // 目前还不做回滚功能，所以MaxRevision就是当前版本的Revision
451			VersionList:    versionList,
452		}, nil
453	}
