455	func listAISuitesInRegistry(ctx *gin.Context, suiteRegistry *db.Repository) ([]*aisuite.ProfileAISuite, error) {
456		if suiteRegistry == nil {
457			return nil, fmt.Errorf("suite registry is nil")
458		}
459	
460		registryOpts := harbor.DefaultOptions().WithPageSize(100).WithPage(1)
461		registryCli, err := harbor.GetRegistryClient(suiteRegistry, registryOpts)
462		if err != nil {
463			log.Errorf("failed to get registry client: %v", err)
464			return nil, err
465		}
466	
467		reposInSuiteRegistry := make([]*model.Repository, 0)
468		for {
469			repos, err := registryCli.GetClient().ListRepositories(ctx, suiteChartProject)
470			if err != nil {
471				log.Errorf("failed to list repositories in suite registry: %v", err)
472				return nil, err
473			}
474			reposInSuiteRegistry = append(reposInSuiteRegistry, repos...)
475			if int64(len(repos)) < registryOpts.PageSize {
476				break
477			}
478			registryOpts = registryOpts.WithPage(registryOpts.Page + 1)
479			if registryOpts.Page > 20 {
480				log.Errorf("too many repositories in suite registry, page: %d, pageSize: %d", registryOpts.Page, registryOpts.PageSize)
481				break
482			}
483		}
484	
485		aiSuites, err := filterAISuitesFromRepos(ctx, suiteRegistry, reposInSuiteRegistry)
486		if err != nil {
487			log.Errorf("failed to get AI Suites from repos: %v", err)
488			return nil, err
489		}
490	
491		return aiSuites, nil
492	
493	}
