204		if !c.insecure {
205			return retry.DefaultClient
206		}
207		return &http.Client{
208			Transport: retry.NewTransport(&http.Transport{
209				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
210			}),
211		}
212	}
